import { useRef } from 'react';
import { useEventListener } from './useEventListener';

export default function App() {
  const boxRef = useRef<HTMLDivElement>(null);

  // Global key listener
  useEventListener('keydown', (e) => {
    console.log('Key pressed:', e.key);
  });

  // Element-level click listener
  useEventListener('click', (e) => {
    console.log('Box clicked at', e.clientX, e.clientY);
  }, boxRef.current ?? undefined);

  return (
    <div style={{ padding: '2rem' }}>
      <p style={{ marginBottom: '1rem', fontSize: '0.875rem', color: '#6b7280' }}>Press any key or click the box. Check the console.</p>
      <div
        ref={boxRef}
        style={{
          width: '12rem',
          height: '8rem',
          border: '2px dashed #d1d5db',
          borderRadius: '0.5rem',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          cursor: 'pointer',
          userSelect: 'none',
        }}
      >
        Click me
      </div>
    </div>
  );
}

